{
  "name": "RemesaControl Pro",
  "description": "Sistema avanzado para el control de remesas con integración de tasas de cambio en tiempo real de El Toque y gestión de trabajadores.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Currency = 'USD' | 'EUR' | 'MLC' | 'CUP';

export interface CurrencyPair {
  id: string;
  base: Currency;
  target: Currency;
  isFavorite: boolean;
}

export interface ExchangeRate {
  pairId: string;
  referenceValue: number;
  manualValue: number;
  useManual: boolean;
  lastUpdated: string;
  sources?: { title: string; uri: string }[];
}

export interface Worker {
  id: string;
  name: string;
  accountInfo: string;
}

export interface Transaction {
  id: string;
  date: string;
  workerId: string;
  amount: number;
  currency: Currency;
  rate: number;
  totalCUP: number;
  description: string;
  status: 'completado' | 'pendiente';
}

export interface AppState {
  transactions: Transaction[];
  workers: Worker[];
  rates: ExchangeRate[];
  favoritePairs: string[];
}

import { CurrencyPair } from './types';

export const INITIAL_CURRENCY_PAIRS: CurrencyPair[] = [
  { id: 'USD-CUP', base: 'USD', target: 'CUP', isFavorite: true },
  { id: 'EUR-CUP', base: 'EUR', target: 'CUP', isFavorite: true },
  { id: 'MLC-CUP', base: 'MLC', target: 'CUP', isFavorite: true },
  { id: 'USD-MLC', base: 'USD', target: 'MLC', isFavorite: false },
];

export const EL_TOQUE_URL = "https://eltoque.com/tasas-de-cambio-de-divisas-en-cuba-hoy";

import { GoogleGenAI } from "@google/genai";
import { ExchangeRate } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchElToqueRates = async (): Promise<{ rates: Partial<Record<string, number>>, sources: { title: string, uri: string }[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Busca las tasas de cambio informales actuales en Cuba del sitio El Toque para USD, EUR y MLC frente al CUP. Devuelve solo los valores numéricos de venta aproximados.",
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Referencia",
      uri: chunk.web?.uri || ""
    })) || [];

    // Basic parsing of the response text to find numbers associated with currencies
    const rates: Partial<Record<string, number>> = {};

    const usdMatch = text.match(/USD[:\s-]+(\d+)/i);
    const eurMatch = text.match(/EUR[:\s-]+(\d+)/i);
    const mlcMatch = text.match(/MLC[:\s-]+(\d+)/i);

    if (usdMatch) rates['USD-CUP'] = parseInt(usdMatch[1]);
    if (eurMatch) rates['EUR-CUP'] = parseInt(eurMatch[1]);
    if (mlcMatch) rates['MLC-CUP'] = parseInt(mlcMatch[1]);

    // Fallbacks if search fails to provide clear numbers
    if (!rates['USD-CUP']) rates['USD-CUP'] = 320; 
    if (!rates['EUR-CUP']) rates['EUR-CUP'] = 330;
    if (!rates['MLC-CUP']) rates['MLC-CUP'] = 275;

    return { rates, sources };
  } catch (error) {
    console.error("Error fetching rates from Gemini:", error);
    return { 
      rates: { 'USD-CUP': 320, 'EUR-CUP': 330, 'MLC-CUP': 275 }, 
      sources: [{ title: "Error en búsqueda", uri: "#" }] 
    };
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, Worker, ExchangeRate, CurrencyPair, Currency } from './types';
import { INITIAL_CURRENCY_PAIRS } from './constants';
import { fetchElToqueRates } from './services/geminiService';
import { 
  LayoutDashboard, 
  ArrowLeftRight, 
  Users, 
  Settings, 
  Plus, 
  TrendingUp, 
  Star, 
  Search,
  RefreshCw,
  Trash2,
  CheckCircle2,
  Clock
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'transactions' | 'workers' | 'settings'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [workers, setWorkers] = useState<Worker[]>([]);
  const [pairs, setPairs] = useState<CurrencyPair[]>(INITIAL_CURRENCY_PAIRS);
  const [rates, setRates] = useState<ExchangeRate[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [showTransactionModal, setShowTransactionModal] = useState(false);

  // Initialize data
  useEffect(() => {
    const savedTransactions = localStorage.getItem('transactions');
    const savedWorkers = localStorage.getItem('workers');
    const savedPairs = localStorage.getItem('pairs');
    const savedRates = localStorage.getItem('rates');

    if (savedTransactions) setTransactions(JSON.parse(savedTransactions));
    if (savedWorkers) setWorkers(JSON.parse(savedWorkers));
    if (savedPairs) setPairs(JSON.parse(savedPairs));
    if (savedRates) setRates(JSON.parse(savedRates));

    refreshRates();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Save data on change
  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
    localStorage.setItem('workers', JSON.stringify(workers));
    localStorage.setItem('pairs', JSON.stringify(pairs));
    localStorage.setItem('rates', JSON.stringify(rates));
  }, [transactions, workers, pairs, rates]);

  const refreshRates = async () => {
    setIsRefreshing(true);
    const { rates: fetchedValues, sources } = await fetchElToqueRates();

    const newRates = pairs.map(pair => {
      const existing = rates.find(r => r.pairId === pair.id);
      const val = fetchedValues[pair.id] || existing?.referenceValue || 0;
      return {
        pairId: pair.id,
        referenceValue: val,
        manualValue: existing?.manualValue || val,
        useManual: existing?.useManual || false,
        lastUpdated: new Date().toISOString(),
        sources
      };
    });

    setRates(newRates);
    setIsRefreshing(false);
  };

  const addTransaction = (t: Omit<Transaction, 'id' | 'date'>) => {
    const newTx: Transaction = {
      ...t,
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString()
    };
    setTransactions([newTx, ...transactions]);
    setShowTransactionModal(false);
  };

  const addWorker = (name: string, account: string) => {
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      accountInfo: account
    };
    setWorkers([...workers, newWorker]);
  };

  const toggleFavorite = (id: string) => {
    setPairs(pairs.map(p => p.id === id ? { ...p, isFavorite: !p.isFavorite } : p));
  };

  const updateRate = (pairId: string, value: number, isManual: boolean) => {
    setRates(rates.map(r => r.pairId === pairId ? { 
      ...r, 
      manualValue: isManual ? value : r.manualValue,
      useManual: isManual 
    } : r));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50">
      {/* Mobile Navigation Bar */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex justify-around p-4 z-50">
        <button onClick={() => setActiveTab('dashboard')} className={`${activeTab === 'dashboard' ? 'text-blue-600' : 'text-gray-500'}`}><LayoutDashboard size={24} /></button>
        <button onClick={() => setActiveTab('transactions')} className={`${activeTab === 'transactions' ? 'text-blue-600' : 'text-gray-500'}`}><ArrowLeftRight size={24} /></button>
        <button onClick={() => setActiveTab('workers')} className={`${activeTab === 'workers' ? 'text-blue-600' : 'text-gray-500'}`}><Users size={24} /></button>
        <button onClick={() => setActiveTab('settings')} className={`${activeTab === 'settings' ? 'text-blue-600' : 'text-gray-500'}`}><Settings size={24} /></button>
      </div>

      {/* Sidebar Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-white border-r border-gray-200 h-screen sticky top-0">
        <div className="p-6 border-b border-gray-100">
          <h1 className="text-xl font-bold text-blue-600 flex items-center gap-2">
            <ArrowLeftRight className="text-blue-500" />
            RemesaControl
          </h1>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<ArrowLeftRight size={20} />} label="Remesas" active={activeTab === 'transactions'} onClick={() => setActiveTab('transactions')} />
          <NavItem icon={<Users size={20} />} label="Trabajadores" active={activeTab === 'workers'} onClick={() => setActiveTab('workers')} />
          <NavItem icon={<Settings size={20} />} label="Configuración" active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} />
        </nav>
        <div className="p-4 border-t border-gray-100">
          <div className="bg-blue-50 rounded-lg p-3">
            <p className="text-xs text-blue-600 font-medium">Soporte Gemini AI</p>
            <p className="text-[10px] text-blue-500 mt-1">Grounding: El Toque Activo</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 pb-24 md:pb-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-gray-800 capitalize">{activeTab}</h2>
            <p className="text-sm text-gray-500">Gestión de remesas y flujo de efectivo</p>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={refreshRates}
              className={`p-2 rounded-lg bg-white border border-gray-200 hover:bg-gray-50 transition-colors ${isRefreshing ? 'animate-spin' : ''}`}
              title="Sincronizar Tasas El Toque"
            >
              <RefreshCw size={20} className="text-gray-600" />
            </button>
            <button 
              onClick={() => setShowTransactionModal(true)}
              className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-all shadow-sm shadow-blue-200"
            >
              <Plus size={20} />
              <span className="hidden sm:inline">Nueva Remesa</span>
            </button>
          </div>
        </header>

        {activeTab === 'dashboard' && (
          <DashboardView 
            transactions={transactions} 
            rates={rates} 
            pairs={pairs} 
            onToggleFavorite={toggleFavorite}
            onUpdateRate={updateRate}
            isRefreshing={isRefreshing}
          />
        )}
        {activeTab === 'transactions' && (
          <TransactionsView 
            transactions={transactions} 
            workers={workers} 
            onDelete={(id) => setTransactions(transactions.filter(t => t.id !== id))}
          />
        )}
        {activeTab === 'workers' && (
          <WorkersView 
            workers={workers} 
            onAdd={addWorker}
            onDelete={(id) => setWorkers(workers.filter(w => w.id !== id))}
          />
        )}
        {activeTab === 'settings' && (
          <SettingsView 
            pairs={pairs}
            onToggleFavorite={toggleFavorite}
          />
        )}
      </main>

      {/* Modal Nueva Remesa */}
      {showTransactionModal && (
        <TransactionModal 
          onClose={() => setShowTransactionModal(false)}
          onSubmit={addTransaction}
          workers={workers}
          rates={rates}
          pairs={pairs}
        />
      )}
    </div>
  );
};

// --- Subcomponents ---

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${active ? 'bg-blue-50 text-blue-600 shadow-sm' : 'text-gray-500 hover:bg-gray-50'}`}
  >
    {icon}
    <span className="font-medium">{label}</span>
  </button>
);

const DashboardView: React.FC<{ 
  transactions: Transaction[], 
  rates: ExchangeRate[], 
  pairs: CurrencyPair[], 
  onToggleFavorite: (id: string) => void,
  onUpdateRate: (id: string, val: number, manual: boolean) => void,
  isRefreshing: boolean
}> = ({ transactions, rates, pairs, onToggleFavorite, onUpdateRate, isRefreshing }) => {
  const totalCUP = transactions.reduce((acc, t) => acc + t.totalCUP, 0);
  const pendingCount = transactions.filter(t => t.status === 'pendiente').length;

  const favoritePairs = pairs.filter(p => p.isFavorite);

  return (
    <div className="space-y-8">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        <StatCard label="Total Movido (CUP)" value={`$${totalCUP.toLocaleString()}`} icon={<TrendingUp className="text-green-500" />} />
        <StatCard label="Remesas Pendientes" value={pendingCount.toString()} icon={<Clock className="text-amber-500" />} />
        <StatCard label="Tasa USD Referencia" value={`${rates.find(r => r.pairId === 'USD-CUP')?.referenceValue || 0} CUP`} icon={<ArrowLeftRight className="text-blue-500" />} />
      </div>

      {/* Rates Section */}
      <section>
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold text-gray-700 flex items-center gap-2">
            <TrendingUp size={20} className="text-blue-500" />
            Tasas de Cambio Activas
          </h3>
          <span className="text-xs text-gray-400">Datos obtenidos de El Toque (Gemini Grounding)</span>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {favoritePairs.map(pair => {
            const rate = rates.find(r => r.pairId === pair.id);
            return (
              <RateCard 
                key={pair.id} 
                pair={pair} 
                rate={rate} 
                onUpdateRate={onUpdateRate}
                onToggleFavorite={onToggleFavorite}
              />
            );
          })}
        </div>
      </section>

      {/* Recent Activity */}
      <section>
        <h3 className="text-lg font-semibold text-gray-700 mb-4">Actividad Reciente</h3>
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Monto</th>
                  <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">CUP Equivalente</th>
                  <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Estado</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {transactions.slice(0, 5).map(tx => (
                  <tr key={tx.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 font-medium">{tx.amount} {tx.currency}</td>
                    <td className="px-6 py-4 text-gray-600">${tx.totalCUP.toLocaleString()}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase ${tx.status === 'completado' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
                        {tx.status}
                      </span>
                    </td>
                  </tr>
                ))}
                {transactions.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-6 py-8 text-center text-gray-400 italic">No hay transacciones registradas</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </section>
    </div>
  );
};

const StatCard: React.FC<{ label: string, value: string, icon: React.ReactNode }> = ({ label, value, icon }) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between">
    <div>
      <p className="text-sm text-gray-500 mb-1">{label}</p>
      <h4 className="text-2xl font-bold text-gray-800">{value}</h4>
    </div>
    <div className="p-3 bg-gray-50 rounded-lg">{icon}</div>
  </div>
);

const RateCard: React.FC<{ pair: CurrencyPair, rate?: ExchangeRate, onUpdateRate: (id: string, val: number, man: boolean) => void, onToggleFavorite: (id: string) => void }> = ({ pair, rate, onUpdateRate, onToggleFavorite }) => {
  const [editing, setEditing] = useState(false);
  const [val, setVal] = useState(rate?.manualValue || 0);

  useEffect(() => {
    if (rate) setVal(rate.manualValue);
  }, [rate]);

  return (
    <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
      <div className="flex justify-between items-start mb-4">
        <div>
          <h4 className="font-bold text-gray-800">{pair.base} / {pair.target}</h4>
          <p className="text-[10px] text-gray-400">Ref: {rate?.referenceValue} CUP</p>
        </div>
        <button onClick={() => onToggleFavorite(pair.id)} className="text-amber-400 hover:text-amber-500">
          <Star fill={pair.isFavorite ? "currentColor" : "none"} size={18} />
        </button>
      </div>

      <div className="space-y-3">
        <div className="flex items-center gap-2">
          {editing ? (
            <input 
              type="number"
              value={val}
              onChange={(e) => setVal(Number(e.target.value))}
              onBlur={() => {
                onUpdateRate(pair.id, val, true);
                setEditing(false);
              }}
              className="w-full bg-gray-50 border border-gray-200 rounded px-2 py-1 text-sm outline-none focus:ring-1 focus:ring-blue-400"
              autoFocus
            />
          ) : (
            <div className="flex-1 text-xl font-bold text-blue-600">
              {rate?.useManual ? rate.manualValue : rate?.referenceValue} 
              <span className="text-xs ml-1 text-gray-400 font-normal">CUP</span>
            </div>
          )}
          <button 
            onClick={() => setEditing(!editing)}
            className="p-1 hover:bg-gray-100 rounded text-gray-400"
          >
            <Settings size={14} />
          </button>
        </div>

        <div className="flex items-center gap-2">
          <label className="relative inline-flex items-center cursor-pointer">
            <input 
              type="checkbox" 
              className="sr-only peer" 
              checked={rate?.useManual} 
              onChange={() => onUpdateRate(pair.id, rate?.manualValue || 0, !rate?.useManual)}
            />
            <div className="w-7 h-4 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-blue-500"></div>
          </label>
          <span className="text-[10px] text-gray-500">Usar tasa manual</span>
        </div>
      </div>
    </div>
  );
};

const TransactionsView: React.FC<{ transactions: Transaction[], workers: Worker[], onDelete: (id: string) => void }> = ({ transactions, workers, onDelete }) => {
  const getWorkerName = (id: string) => workers.find(w => w.id === id)?.name || "N/A";

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-6 border-b border-gray-100 flex items-center justify-between">
        <h3 className="font-bold text-gray-800">Historial de Remesas</h3>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input 
            type="text" 
            placeholder="Buscar transacciones..." 
            className="pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-400 transition-all"
          />
        </div>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b border-gray-100">
            <tr>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Fecha</th>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Trabajador</th>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Enviado</th>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Tasa</th>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Recibe (CUP)</th>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase">Estado</th>
              <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {transactions.map(tx => (
              <tr key={tx.id} className="hover:bg-gray-50">
                <td className="px-6 py-4 text-xs text-gray-500">
                  {new Date(tx.date).toLocaleDateString()}
                </td>
                <td className="px-6 py-4 font-medium text-gray-800">
                  {getWorkerName(tx.workerId)}
                </td>
                <td className="px-6 py-4 text-gray-600 font-semibold">
                  {tx.amount} {tx.currency}
                </td>
                <td className="px-6 py-4 text-xs text-gray-400">
                  1:{tx.rate}
                </td>
                <td className="px-6 py-4 font-bold text-blue-600">
                  ${tx.totalCUP.toLocaleString()}
                </td>
                <td className="px-6 py-4">
                  <div className={`flex items-center gap-1 text-[10px] font-bold uppercase ${tx.status === 'completado' ? 'text-green-600' : 'text-amber-600'}`}>
                    {tx.status === 'completado' ? <CheckCircle2 size={12} /> : <Clock size={12} />}
                    {tx.status}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <button onClick={() => onDelete(tx.id)} className="p-1 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded">
                    <Trash2 size={16} />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const WorkersView: React.FC<{ workers: Worker[], onAdd: (n: string, a: string) => void, onDelete: (id: string) => void }> = ({ workers, onAdd, onDelete }) => {
  const [name, setName] = useState('');
  const [account, setAccount] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name && account) {
      onAdd(name, account);
      setName('');
      setAccount('');
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-1">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="font-bold text-gray-800 mb-4">Agregar Trabajador</h3>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Nombre Completo</label>
              <input 
                type="text" 
                value={name}
                onChange={e => setName(e.target.value)}
                placeholder="Ej. Juan Perez" 
                className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-400"
              />
            </div>
            <div>
