export const EL_TOQUE_URL = "https://eltoque.com/tasas-de-cambio-de-divisas-en-cuba-hoy";

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchElToqueRates = async (): Promise<{ ratesInCUP: Record<string, number>, sources: { title: string, uri: string }[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Busca los valores actuales de venta en el mercado informal de Cuba (referencia El Toque) para las siguientes divisas y métodos, expresados en pesos cubanos (CUP):
      USD, EUR, MLC, USDT, Zelle, PayPal (USD/EUR), MXN, Real Brasileño, Rublos.
      Devuelve solo una lista de moneda: valor.`,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Referencia Mercado",
      uri: chunk.web?.uri || ""
    })) || [];

    const rates: Record<string, number> = { 'CUP': 1 }; // Base

    const extract = (regex: RegExp, fallback: number) => {
      const match = text.match(regex);
      return match ? parseInt(match[1]) : fallback;
    };

    const baseUSD = extract(/USD[:\s-]+(\d+)/i, 320);
    const baseEUR = extract(/EUR[:\s-]+(\d+)/i, 330);
    const baseMLC = extract(/MLC[:\s-]+(\d+)/i, 275);

    rates['USD'] = baseUSD;
    rates['EUR'] = baseEUR;
    rates['MLC'] = baseMLC;
    rates['USDT'] = extract(/USDT[:\s-]+(\d+)/i, baseUSD);
    rates['Zelle'] = baseUSD;
    rates['PAYPALUSD'] = baseUSD - 15;
    rates['PAYPALEUR'] = baseEUR - 15;
    rates['MXN'] = extract(/MXN[:\s-]+(\d+)/i, 15);
    rates['Real'] = extract(/Real[:\s-]+(\d+)/i, 55);
    rates['Rublos'] = extract(/Rublos[:\s-]+(\d+)/i, 3.2);
    rates['Bizum'] = baseEUR;
    rates['IBAN'] = baseEUR;
    rates['Tropipay'] = baseEUR;
    rates['MoneyGram'] = baseUSD;
    rates['WesternUnion'] = baseUSD;
    rates['CLASICA'] = baseUSD;
    rates['Postepey'] = baseUSD;
    rates['NOAHSYNC'] = baseUSD;

    return { ratesInCUP: rates, sources };
  } catch (error) {
    console.error("Error fetching rates:", error);
    return { 
      ratesInCUP: { 'USD': 320, 'EUR': 330, 'CUP': 1, 'MLC': 275 }, 
      sources: [] 
    };
  }
};

