  const [manualRates, setManualRates] = useState<Record<string, { val: number, active: boolean }>>({});
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [showTransactionModal, setShowTransactionModal] = useState(false);

  useEffect(() => {
    const saved = (key: string) => localStorage.getItem(key);
    if (saved('transactions')) setTransactions(JSON.parse(saved('transactions')!));
    if (saved('workers')) setWorkers(JSON.parse(saved('workers')!));
    if (saved('pairs')) setPairs(JSON.parse(saved('pairs')!));
    if (saved('manualRates')) setManualRates(JSON.parse(saved('manualRates')!));
    refreshRates();
  }, []);

  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
    localStorage.setItem('workers', JSON.stringify(workers));
    localStorage.setItem('pairs', JSON.stringify(pairs));
    localStorage.setItem('manualRates', JSON.stringify(manualRates));
  }, [transactions, workers, pairs, manualRates]);

  const refreshRates = async () => {
    setIsRefreshing(true);
    const { ratesInCUP } = await fetchElToqueRates();
    setBaseRatesInCUP(ratesInCUP);
    setIsRefreshing(false);
  };

  const getEffectiveRate = (from: Currency, to: Currency) => {
    const pairId = `${from}-${to}`;
    if (manualRates[pairId]?.active) return manualRates[pairId].val;

    const fromInCUP = baseRatesInCUP[from] || 0;
    const toInCUP = baseRatesInCUP[to] || 1;
    if (toInCUP === 0) return 0;

    return Number((fromInCUP / toInCUP).toFixed(4));
  };

  const addTransaction = (t: Omit<Transaction, 'id' | 'date'>) => {
    const newTx: Transaction = {
      ...t,
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString()
    };
    setTransactions([newTx, ...transactions]);
    setShowTransactionModal(false);
  };

  const toggleFavorite = (id: string) => {
    setPairs(pairs.map(p => p.id === id ? { ...p, isFavorite: !p.isFavorite } : p));
  };

  const updateManualRate = (pairId: string, val: number, active: boolean) => {
    setManualRates(prev => ({ ...prev, [pairId]: { val, active } }));
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-gray-50 text-gray-900">
      {/* Mobile Nav */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex justify-around p-4 z-50">
        <button onClick={() => setActiveTab('dashboard')} className={`${activeTab === 'dashboard' ? 'text-blue-600' : 'text-gray-400'}`}><LayoutDashboard size={24} /></button>
        <button onClick={() => setActiveTab('transactions')} className={`${activeTab === 'transactions' ? 'text-blue-600' : 'text-gray-400'}`}><ArrowLeftRight size={24} /></button>
        <button onClick={() => setActiveTab('workers')} className={`${activeTab === 'workers' ? 'text-blue-600' : 'text-gray-400'}`}><Users size={24} /></button>
        <button onClick={() => setActiveTab('settings')} className={`${activeTab === 'settings' ? 'text-blue-600' : 'text-gray-400'}`}><Settings size={24} /></button>
      </div>

      {/* Sidebar Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-white border-r border-gray-200 h-screen sticky top-0">
        <div className="p-6 border-b border-gray-100">
          <h1 className="text-xl font-bold text-blue-600 flex items-center gap-2">
            <ArrowLeftRight className="text-blue-500" />
            RemesaControl
          </h1>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <NavItem icon={<ArrowLeftRight size={20} />} label="Remesas" active={activeTab === 'transactions'} onClick={() => setActiveTab('transactions')} />
          <NavItem icon={<Users size={20} />} label="Trabajadores" active={activeTab === 'workers'} onClick={() => setActiveTab('workers')} />
          <NavItem icon={<Settings size={20} />} label="Divisas" active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} />
        </nav>
      </aside>

      <main className="flex-1 p-4 md:p-8 pb-24 md:pb-8 max-w-7xl mx-auto w-full">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-gray-800">
              {activeTab === 'dashboard' ? 'Tasas y Favoritos' : activeTab === 'transactions' ? 'Movimientos' : activeTab === 'workers' ? 'Trabajadores' : 'Configuración'}
            </h2>
            <p className="text-sm text-gray-500">Sistema Multi-Divisa Automático</p>
          </div>
          <div className="flex gap-2">
            <button onClick={refreshRates} className={`p-2 rounded-lg bg-white border border-gray-200 hover:bg-gray-50 ${isRefreshing ? 'animate-spin' : ''}`}>
              <RefreshCw size={20} />
            </button>
            <button onClick={() => setShowTransactionModal(true)} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 shadow-lg shadow-blue-100 transition-all active:scale-95">
              <Plus size={20} />
              <span>Nueva Remesa</span>
            </button>
          </div>
        </header>

        {activeTab === 'dashboard' && (
          <DashboardView 
            transactions={transactions} 
            baseRates={baseRatesInCUP} 
            manualRates={manualRates}
            pairs={pairs} 
            onUpdateManual={updateManualRate}
            getEffectiveRate={getEffectiveRate}
          />
        )}
        {activeTab === 'transactions' && (
          <TransactionsView transactions={transactions} workers={workers} onDelete={(id) => setTransactions(transactions.filter(t => t.id !== id))} />
        )}
        {activeTab === 'workers' && (
          <WorkersView workers={workers} onAdd={(n, a) => setWorkers([...workers, { id: Math.random().toString(36).substr(2, 9), name: n, accountInfo: a }])} onDelete={(id) => setWorkers(workers.filter(w => w.id !== id))} />
        )}
        {activeTab === 'settings' && (
          <SettingsView pairs={pairs} onToggleFavorite={toggleFavorite} onAddPair={(b, t) => setPairs([...pairs, { id: `${b}-${t}`, base: b, target: t, isFavorite: true }])} />
        )}
      </main>

      {showTransactionModal && (
        <TransactionModal 
          onClose={() => setShowTransactionModal(false)}
          onSubmit={addTransaction}
          workers={workers}
          getRate={getEffectiveRate}
        />
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${active ? 'bg-blue-50 text-blue-600 font-bold' : 'text-gray-500 hover:bg-gray-50'}`}>
    {icon}
    <span>{label}</span>
  </button>
);

const DashboardView: React.FC<{ 
  transactions: Transaction[], 
  baseRates: Record<string, number>, 
  manualRates: Record<string, { val: number, active: boolean }>,
  pairs: CurrencyPair[],
  onUpdateManual: (id: string, v: number, a: boolean) => void,
  getEffectiveRate: (f: Currency, t: Currency) => number
}> = ({ transactions, baseRates, manualRates, pairs, onUpdateManual, getEffectiveRate }) => {
  const favoritePairs = pairs.filter(p => p.isFavorite);

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {favoritePairs.map(pair => {
          const rate = getEffectiveRate(pair.base, pair.target);
          const manual = manualRates[pair.id];
          return (
            <div key={pair.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow">
              <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-2">
                  <div className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center font-black text-xs">
                    {pair.base.substring(0, 3)}
                  </div>
                  <ArrowRight size={14} className="text-gray-300" />
                  <div className="w-10 h-10 rounded-xl bg-gray-50 text-gray-600 flex items-center justify-center font-black text-xs">
                    {pair.target.substring(0, 3)}
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{pair.base} → {pair.target}</p>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex items-end gap-2">
                  <span className="text-3xl font-black text-blue-600">{rate}</span>
                  <span className="text-sm font-bold text-gray-400 mb-1">{pair.target}</span>
                </div>

                <div className="pt-4 border-t border-gray-50 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <label className="relative inline-flex items-center cursor-pointer">
                      <input 
                        type="checkbox" 
                        className="sr-only peer" 
                        checked={manual?.active || false} 
                        onChange={(e) => onUpdateManual(pair.id, manual?.val || rate, e.target.checked)}
                      />
                      <div className="w-8 h-4 bg-gray-200 rounded-full peer peer-checked:bg-blue-500 after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:after:translate-x-full"></div>
                    </label>
                    <span className="text-[10px] font-bold text-gray-500">TASA FIJA</span>
                  </div>
                  {manual?.active && (
                    <input 
                      type="number" 
                      value={manual.val} 
                      onChange={(e) => onUpdateManual(pair.id, Number(e.target.value), true)}
                      className="w-20 bg-gray-50 border border-gray-200 rounded px-2 py-1 text-xs font-bold outline-none focus:ring-1 focus:ring-blue-400"
                    />
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

