            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Fecha / Destino</th>
            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Envía</th>
            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Recibe</th>
            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider">Tasa Aplicada</th>
            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-wider"></th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
