        <textarea placeholder="Cuenta / Datos de Pago" value={a} onChange={e => setA(e.target.value)} rows={3} className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
        <button onClick={() => { onAdd(n, a); setN(''); setA(''); }} className="w-full bg-blue-600 text-white py-2 rounded-xl font-bold hover:bg-blue-700 transition-all">Guardar</button>
