              <p className="text-xs text-gray-400 mt-2 whitespace-pre-wrap">{w.accountInfo}</p>
            </div>
            <button onClick={() => onDelete(w.id)} className="text-gray-200 hover:text-red-500 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
          </div>
        ))}
      </div>
    </div>
