};

const SettingsView: React.FC<{ pairs: CurrencyPair[], onToggleFavorite: (id: string) => void, onAddPair: (f: Currency, t: Currency) => void }> = ({ pairs, onToggleFavorite, onAddPair }) => {
  const [from, setFrom] = useState<Currency>('USD');
  const [to, setTo] = useState<Currency>('CUP');
  return (
    <div className="max-w-2xl space-y-8">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
        <h3 className="font-bold text-gray-800 mb-6">Nuevo Par Favorito</h3>
        <div className="flex items-center gap-4 mb-8">
          <select value={from} onChange={e => setFrom(e.target.value as Currency)} className="flex-1 px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold">
            {ALL_CURRENCIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <ArrowRight className="text-gray-300" />
          <select value={to} onChange={e => setTo(e.target.value as Currency)} className="flex-1 px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold">
            {ALL_CURRENCIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button onClick={() => onAddPair(from, to)} className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-700 transition-all"><Plus /></button>
