            <div key={p.id} className="flex items-center justify-between p-3 bg-gray-50/50 rounded-xl border border-gray-100">
              <span className="font-bold text-sm text-gray-600">{p.base} → {p.target}</span>
              <button onClick={() => onToggleFavorite(p.id)} className={`p-1 ${p.isFavorite ? 'text-amber-500' : 'text-gray-300'}`}><Star fill={p.isFavorite ? "currentColor" : "none"} size={18} /></button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

const TransactionModal: React.FC<{ 
  onClose: () => void, 
  onSubmit: (t: Omit<Transaction, 'id' | 'date'>) => void,
  workers: Worker[],
  getRate: (f: Currency, t: Currency) => number
}> = ({ onClose, onSubmit, workers, getRate }) => {
  const [amount, setAmount] = useState<string>('0');
  const [from, setFrom] = useState<Currency>('USD');
  const [to, setTo] = useState<Currency>('CUP');
  const [workerId, setWorkerId] = useState(workers[0]?.id || '');
  const [manualRate, setManualRate] = useState<number>(0);
  const [isManual, setIsManual] = useState(false);

  const suggestedRate = useMemo(() => getRate(from, to), [from, to, getRate]);
  const activeRate = isManual ? manualRate : suggestedRate;
  const total = Number(amount) * activeRate;

  useEffect(() => {
    if (!isManual) setManualRate(suggestedRate);
  }, [suggestedRate, isManual]);

  return (
    <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
      <div className="bg-white w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
        <div className="p-8 bg-blue-600 text-white flex justify-between items-start">
          <div>
            <h3 className="text-2xl font-black">Registrar Remesa</h3>
            <p className="text-blue-100 text-xs font-bold uppercase tracking-widest mt-1">Multi-Divisa Universal</p>
          </div>
          <button onClick={onClose} className="hover:bg-white/20 p-2 rounded-full transition-colors"><Plus className="rotate-45" size={24} /></button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onSubmit({ workerId, amount: Number(amount), currency: from, rate: activeRate, totalCUP: total, description: '', status: 'completado' }); }} className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Monto Envía</label>
              <input type="number" value={amount} onChange={e => setAmount(e.target.value)} className="w-full px-4 py-4 bg-gray-50 border border-gray-200 rounded-2xl text-2xl font-black outline-none focus:ring-2 focus:ring-blue-500 transition-all" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Divisa Origen</label>
              <select value={from} onChange={e => setFrom(e.target.value as Currency)} className="w-full px-4 py-4 bg-gray-50 border border-gray-200 rounded-2xl text-xl font-bold outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer">
                {ALL_CURRENCIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Destinatario</label>
              <select value={workerId} onChange={e => setWorkerId(e.target.value)} className="w-full px-4 py-4 bg-gray-50 border border-gray-200 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer" required>
                <option value="">Selecciona trabajador...</option>
                {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Divisa Destino</label>
              <select value={to} onChange={e => setTo(e.target.value as Currency)} className="w-full px-4 py-4 bg-gray-50 border border-gray-200 rounded-2xl text-xl font-bold outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer">
                {ALL_CURRENCIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>

          <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100 space-y-4">
            <div className="flex justify-between items-center">
              <div>
                <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Tasa de Cambio</span>
                <div className="flex items-center gap-3">
                  <input 
                    type="number" 
                    value={activeRate} 
                    onChange={e => { setManualRate(Number(e.target.value)); setIsManual(true); }}
                    className="w-24 bg-white border border-gray-200 rounded-lg px-2 py-1 font-black text-blue-600 outline-none focus:ring-2 focus:ring-blue-500"
                  />
                  <button type="button" onClick={() => setIsManual(false)} className={`text-[10px] font-bold px-2 py-1 rounded ${!isManual ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:text-gray-600'}`}>RESET</button>
                </div>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Total a Entregar</span>
                <div className="text-2xl font-black text-blue-700 leading-none">
                  {total.toLocaleString(undefined, { maximumFractionDigits: 2 })}
                  <span className="text-[10px] ml-1 text-blue-400">{to}</span>
                </div>
              </div>
            </div>
          </div>

          <button type="submit" className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-[0.98]">
            REGISTRAR MOVIMIENTO
          </button>
        </form>
      </div>
    </div>
  );
};

export default App;
